const results = items[0].json.results || []
const cfg = {
  maxPrice: 400,
  minDiscountPct: 10
}
const store = getWorkflowStaticData('global')
if (!store.seen) {
  store.seen = []
}
const fresh = []
for (const product of results) {
  const price = product.price
  const original = product.original_price || price
  const discount = original > price ? (1 - price / original) * 100 : 0
  const wasSeen = store.seen.includes(product.id)
  if (!wasSeen && price <= cfg.maxPrice && discount >= cfg.minDiscountPct) {
    fresh.push({
      id: product.id,
      title: product.title,
      price: price,
      original_price: original,
      discount_pct: Number(discount.toFixed(1)),
      permalink: product.permalink,
      thumbnail: product.thumbnail,
      shipping: product.shipping?.free_shipping ? 'Frete grÃ¡tis' : 'Frete calculado',
      seller_level: product.seller?.seller_reputation?.level_id || ''
    })
  }
}
if (fresh.length === 0) {
  return []
}
store.seen = [...fresh.map(f => f.id), ...store.seen].slice(0, 50)
return fresh.map(f => ({ json: f }))

const cfg = $item(0).$node['Config Cron']?.json || {};
const campaignId = cfg.ML_CAMPAIGN_ID || 'COLOQUE_SEU_CAMPAIGN_ID';
const utm = 'utm_source=whatsapp&utm_medium=grupo&utm_campaign=afiliados';
return items.map(item => {
  const link = `${item.json.permalink}?tool=linkgenerator&campaign_id=${campaignId}&${utm}`;
  const message = [
    '💥 Oferta Mercado Livre',
    `Produto: ${item.json.title}`,
    `Preço: R$ ${item.json.price.toFixed(2)}`,
    item.json.original_price > item.json.price ? `Antes: R$ ${item.json.original_price.toFixed(2)} (-${item.json.discount_pct}% )` : null,
    item.json.shipping,
    '',
    `Link: ${link}`
  ].filter(Boolean).join('
');
  return { json: { ...item.json, affiliate_link: link, message } };
});
